/**
 * @summary Salary history for a single employee
 */
export const getGetEmployeePayrollHistoryUrl = (
  employeeId: number,
  params?: GetEmployeePayrollHistoryParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/payroll/employee/${employeeId}?${stringifiedParams}`
    : `/api/payroll/employee/${employeeId}`;
};

